const fmtVnd = (m) => `${Math.round(m * 1e6).toLocaleString("vi-VN")} ₫`;
function weekRangesFrom(start) {
  const out = [];
  for (let i = 0; i < 13; i++) {
    const a = new Date(start); a.setDate(start.getDate() + i * 7);
    const b = new Date(a); b.setDate(a.getDate() + 6);
    const f = (d) => `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}`;
    out.push(`${f(a)}–${f(b)}`);
  }
  return out;
}
const RANGES = weekRangesFrom(new Date(2026, 5, 1));

/* Bộ dữ liệu cấp cho mô phỏng: demo mặc định, thay bằng số thật khi công ty có dữ liệu.
   Đơn vị tiền trong dataset: TRIỆU đồng. */
const DEMO_DS = { recv: RECV, inflow: INFLOW, outflow: OUTFLOW, startCash: START_CASH, ranges: RANGES, real: false };
/* Bản chính khi công ty chưa nhập gì: KHÔNG hiện số demo — dataset rỗng + lời nhắc nhập liệu */
const EMPTY_DS = { recv: [], inflow: Array(13).fill(0), outflow: Array(13).fill(0), startCash: 0, ranges: weekRangesFrom(new Date()), real: true, empty: true };
const shortName = (r) => (r ? SHORT[r.id] || String(r.name).trim().split(/\s+/).slice(-2).join(" ") : "");

/** Dựng dataset thật từ dữ liệu DB (receivables/payables/openingCash — đơn vị VND). */
function buildRealDS(data) {
  const today = new Date(); today.setHours(0, 0, 0, 0);
  const DAY = 86400000;
  const recv = (data.receivables || [])
    .filter((r) => r.status !== "paid")
    .map((r) => {
      const dd = Math.round((new Date(r.dueDate) - today) / DAY); // số ngày tới hạn (âm = quá hạn)
      const base = {
        id: r.id,
        name: r.customer,
        code: r.invoiceNo ? `HĐ ${r.invoiceNo}` : "—",
        amount: (Number(r.amount) || 0) / 1e6,
        days: Math.max(0, -dd),                       // số ngày quá hạn
        onTime: 0.85,                                  // chưa có lịch sử trả → mặc định
        collectWeek: clamp(Math.floor(Math.max(0, dd) / 7), 0, 12),
        ai: false,
        fromInvoice: r.source === "invoice",
      };
      return { ...base, p: recoverP(base) };
    });
  const outflow = Array(13).fill(0);
  (data.payables || [])
    .filter((p) => p.status !== "paid")
    .forEach((p) => {
      const w = clamp(Math.floor((new Date(p.dueDate) - today) / (7 * DAY)), 0, 12);
      outflow[w] += (Number(p.amount) || 0) / 1e6;
    });
  return {
    recv,
    inflow: Array(13).fill(0), // v1: tiền vào = thu hồi công nợ; doanh thu định kỳ chưa nhập
    outflow,
    startCash: (Number(data.openingCash) || 0) / 1e6,
    ranges: weekRangesFrom(today),
    real: true,
  };
}
function mulberry32(a) {
  return function () {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const pct = (arr, q) => { const a = [...arr].sort((x, y) => x - y); return a[Math.floor(q * (a.length - 1))]; };

function simulate(selectedSet, sc, seed, RUNS = 1400, ds = DEMO_DS) {
  const rng = mulberry32(seed);
  const gauss = () => { let u = 0, v = 0; while (u === 0) u = rng(); while (v === 0) v = rng(); return Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v); };
  const weekly = Array.from({ length: 13 }, () => []); const negAt = Array(13).fill(0); const mins = [];
  for (let run = 0; run < RUNS; run++) {
    const collectAt = Array(13).fill(0);
    for (const r of ds.recv) {
      const pEff = clamp(r.p * (1 - sc.haircut), 0, 0.99);
      const hit = rng() < pEff; const slip = rng() < 0.4 ? 1 : 0;
      if (selectedSet.has(r.id) && hit) { let w = r.collectWeek + sc.delay + slip; if (w > 12) w = 12; collectAt[w] += r.amount; }
    }
    let bal = ds.startCash, mn = Infinity;
    for (let i = 0; i < 13; i++) {
      const rev = ds.inflow[i] * (1 + sc.rev) * (1 + gauss() * sc.revSd);
      bal += rev - ds.outflow[i] * (1 + sc.cost) + collectAt[i];
      weekly[i].push(bal); if (bal < 0) negAt[i]++; if (bal < mn) mn = bal;
    }
    mins.push(mn);
  }
  const data = ds.ranges.map((rg, i) => ({ name: `T${i + 1}`, range: rg, idx: i, p10: pct(weekly[i], 0.1), p50: pct(weekly[i], 0.5), p90: pct(weekly[i], 0.9), band: [pct(weekly[i], 0.1), pct(weekly[i], 0.9)], negShare: negAt[i] / RUNS }));
  const pNeg = mins.filter((m) => m < 0).length / RUNS;
  let riskWeek = 0; data.forEach((d, i) => { if (d.negShare > data[riskWeek].negShare) riskWeek = i; });
  return { data, pNeg, expMin: pct(mins, 0.5), worstMin: pct(mins, 0.1), riskWeek, firstP50Neg: data.findIndex((d) => d.p50 < 0) };
}
function optimize(sc, seed, target, ds = DEMO_DS) {
  // duyệt tổ hợp 2^n — giới hạn 8 khoản lớn nhất để không treo UI khi dữ liệu thật nhiều dòng
  const pool = [...ds.recv].sort((a, b) => b.amount - a.amount).slice(0, 8);
  const ids = pool.map((r) => r.id); let best = null;
  for (let mask = 1; mask < (1 << ids.length); mask++) {
    const set = new Set(); let count = 0, effort = 0;
    ids.forEach((id, i) => { if (mask & (1 << i)) { set.add(id); count++; } });
    pool.forEach((r) => { if (set.has(r.id)) effort += 1 - clamp(r.p * (1 - sc.haircut), 0, 0.99); });
    const { pNeg } = simulate(set, sc, seed, 500, ds);
    if (pNeg <= target) { if (!best || count < best.count || (count === best.count && effort < best.effort)) best = { ids: [...set], count, effort, pNeg }; }
  }
  if (best) return { ...best, feasible: true };
  return { ids, count: ids.length, pNeg: simulate(new Set(ids), sc, seed, 800, ds).pNeg, feasible: false };
}
function riskLevel(p, pal) {
  if (p < 0.10) return { t: "An toàn", key: "safe", c: pal.green, Icon: ShieldCheck };
  if (p < 0.35) return { t: "Cần theo dõi", key: "watch", c: pal.gold, Icon: Activity };
  if (p < 0.65) return { t: "Cảnh báo", key: "warn", c: pal.orange, Icon: AlertTriangle };
  return { t: "Nguy cấp", key: "crit", c: pal.red, Icon: ShieldAlert };
}
const RK_LABEL = { safe: "cf.lvl.safe2", watch: "cf.lvl.watch", warn: "cf.lvl.warn2", crit: "cf.lvl.crit" };
const heat = (s, pal) => (s < 0.05 ? pal.green : s < 0.25 ? pal.gold : s < 0.5 ? pal.orange : pal.red);

function CashflowDashboard() {
  const { t, i18n: i18nInst } = useT();
  const lang = i18nInst.language;
  const { company } = useCompany();
  const currency = company?.currency || "VND";
  const standard = company?.accountingStandard || "VAS";
  const fmtVnd = (m) => fmtMoneyM(m, currency);
  const fmtTr = (m) => fmtCompactM(m, currency);
  const [selected, setSelected] = useState(() => new Set(["r1", "r2"]));
  const [scKey, setScKey] = useState("base");
  const [custom, setCustom] = useState({ rev: -0.20, cost: 0.05, delay: 2, haircut: 0.20 });
  const [target, setTarget] = useState(0.10);
  const [plan, setPlan] = useState(null);
  const [showReport, setShowReport] = useState(false);
  const [srcOpen, setSrcOpen] = useState(false);
  const [connected, setConnected] = useState(() => new Set(["misa"]));
  const [cfData, setCfData] = useState(null);     // dữ liệu thật từ Supabase (null = chưa có/đang tải)
  const [showData, setShowData] = useState(false); // modal nhập liệu

  const reloadCf = () => {
    if (!company?.id) { setCfData(null); return; }
    fetchCashflowData(company.id).then(setCfData).catch(() => setCfData(null));
  };
  useEffect(() => { setCfData(null); reloadCf(); }, [company?.id]);

  // dataset cấp cho mô phỏng: bản demo dùng số minh họa; bản chính CHỈ dùng số thật (chưa có → trống)
  const ds = useMemo(() => (DEMO_MODE ? DEMO_DS : cfData && cfData.hasReal ? buildRealDS(cfData) : EMPTY_DS), [cfData]);
  // phân loại TT200/IFRS — khai báo SAU cfData (tránh lỗi TDZ ở bản build production).
  // Bản chính CHỈ dựng từ số thật; chưa có dữ liệu → rỗng (KHÔNG mượn số minh họa).
  const classification = useMemo(() => {
    if (DEMO_MODE) return standard === "IFRS" ? CLASSIFICATION_IFRS : CLASSIFICATION;
    return cfData && cfData.hasReal ? buildClassificationReal(cfData, standard) : [];
  }, [cfData, standard]);
  useEffect(() => {
    setPlan(null);
    setSelected(ds.real ? new Set(ds.recv.map((r) => r.id)) : new Set(["r1", "r2"]));
  }, [ds]);

  useEffect(() => {
    const l = document.createElement("link"); l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Sora:wght@600;700;800&family=IBM+Plex+Mono:wght@400;500;600&display=swap";
    document.head.appendChild(l); return () => { document.head.removeChild(l); };
  }, []);

  const toggle = (id) => { setPlan(null); setSelected((s) => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; }); };
  const toggleConnect = (id) => setConnected((s) => { const n = new Set(s); n.has(id) ? n.delete(id) : n.add(id); return n; });
  const sc = useMemo(() => scKey === "custom" ? { key: "custom", name: "Tùy chỉnh", ...custom, revSd: clamp(0.06 + Math.abs(custom.rev) * 0.35, 0.06, 0.22) } : PRESETS.find((s) => s.key === scKey), [scKey, custom]);
  const seed = useMemo(() => { let h = 7; const str = scKey + JSON.stringify(custom) + [...selected].sort().join(""); for (let i = 0; i < str.length; i++) h = (h * 31 + str.charCodeAt(i)) | 0; return h >>> 0; }, [selected, scKey, custom]);
  const sim = useMemo(() => simulate(selected, sc, seed, 1400, ds), [selected, sc, seed, ds]);
  const rk = riskLevel(sim.pNeg, C);
  const totalEV = ds.recv.filter((r) => selected.has(r.id)).reduce((s, r) => s + r.amount * clamp(r.p * (1 - sc.haircut), 0, 0.99), 0);
  const yMin = Math.min(0, ...sim.data.map((d) => d.p10)); const yMax = Math.max(ds.startCash, ...sim.data.map((d) => d.p90));

  const runOptimize = () => { const res = optimize(sc, seed, target, ds); setPlan({ ...res, before: sim.pNeg }); setSelected(new Set(res.ids)); };
  const exportExcel = () => {
    const scName = sc.key === "custom" ? t("cf.sc.custom") : t("sc." + sc.key);
    const wb = XLSX.utils.book_new();
    const ov = [[t("cf.xls.title")], [t("cf.xls.company"), COMPANY], [t("cf.xls.date"), new Date().toLocaleDateString(lang === "en" ? "en-US" : "vi-VN")], [t("cf.xls.scenario"), scName], [t("cf.xls.pneg13w"), `${Math.round(sim.pNeg * 100)}%`], [t("cf.xls.risklevel"), t(RK_LABEL[rk.key])], [t("cf.xls.trough"), fmtVnd(sim.expMin)], [t("cf.xls.worst"), fmtVnd(sim.worstMin)], [t("cf.xls.riskweek"), t("cf.xls.weekOf", { w: sim.riskWeek + 1, range: ds.ranges[sim.riskWeek] })], [t("cf.xls.evselected"), fmtVnd(totalEV)], [t("cf.xls.startcash"), fmtVnd(ds.startCash)]];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(ov), t("cf.xls.sheet.overview"));
    const fc = [[t("cf.xls.col.week"), t("cf.xls.col.range"), "P10 (tr)", "P50 (tr)", "P90 (tr)", t("cf.xls.col.inflow"), t("cf.xls.col.outflow"), t("cf.xls.col.risk")]];
    sim.data.forEach((d) => fc.push([d.idx + 1, d.range, Math.round(d.p10), Math.round(d.p50), Math.round(d.p90), Math.round(ds.inflow[d.idx]), Math.round(ds.outflow[d.idx]), `${Math.round(d.negShare * 100)}%`]));
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(fc), t("cf.xls.sheet.forecast"));
    const dl = [[t("cf.xls.col.customer"), t("cf.xls.col.acc"), t("cf.xls.col.debt"), t("cf.xls.col.overdue"), t("cf.xls.col.onTime"), t("cf.xls.col.prob"), t("cf.xls.col.ev"), t("cf.xls.col.collectW"), t("cf.xls.col.inPlan")]];
    ds.recv.forEach((r) => { const pEff = clamp(r.p * (1 - sc.haircut), 0, 0.99); dl.push([r.name, r.code, r.amount, r.days, `${Math.round(r.onTime * 100)}%`, `${Math.round(pEff * 100)}%`, Math.round(r.amount * pEff), `T${Math.min(13, r.collectWeek + sc.delay + 1)}`, selected.has(r.id) ? t("cf.xls.yes") : ""]); });
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(dl), t("cf.xls.sheet.receivables"));
    XLSX.writeFile(wb, "BaoCao_DongTienAI.xlsx");
  };

  if (showReport) return <Report sim={sim} sc={sc} selected={selected} totalEV={totalEV} ds={ds} onClose={() => setShowReport(false)} />;

  return (
    <div style={{ fontFamily: UI, color: C.txt }}>
      <style>{`
        *{box-sizing:border-box}
        @keyframes rise{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}
        .card{animation:rise .5s cubic-bezier(.2,.7,.3,1) both}
        .rowh:hover{background:rgba(255,255,255,.03)}
        .tnum{font-family:${MONO};font-variant-numeric:tabular-nums}
        .btn{cursor:pointer;transition:all .15s;border:none;font-family:${UI}}
        .btn:hover{filter:brightness(1.08)}
        input[type=range]{accent-color:${C.violet};height:4px}
        ::-webkit-scrollbar{height:8px;width:8px}::-webkit-scrollbar-thumb{background:rgba(255,255,255,.1);border-radius:8px}
      `}</style>
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        <header style={{ display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", justifyContent: "space-between", marginBottom: 18 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
            <div style={{ width: 42, height: 42, borderRadius: 12, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${C.gold}, #C9892A)` }}><Wallet size={22} color="#1a1206" strokeWidth={2.4} /></div>
            <div><div style={{ fontFamily: DISP, fontWeight: 800, fontSize: 19, letterSpacing: "-0.02em" }}>{t("cf.title")}</div><div style={{ fontSize: 12.5, color: C.sub, marginTop: 1 }}>{t("cf.subtitle")}</div></div>
          </div>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
            <button className="btn" onClick={exportExcel} style={expBtn(C.green, C.greenSoft)}><FileDown size={15} />{t("cf.exportExcel")}</button>
            <button className="btn" onClick={() => setShowReport(true)} style={expBtn(C.cyan, C.cyanSoft)}><FileText size={15} />{t("cf.reportPDF")}</button>
          </div>
        </header>

        {showData && <CashflowDataModal companyId={company?.id} data={cfData} onChanged={reloadCf} onClose={() => setShowData(false)} />}

        {/* bản chính: lối vào nhập/cập nhật dữ liệu — nút "Nhập dữ liệu" duy nhất của module */}
        {!DEMO_MODE && (
          <div className="card" style={{ ...panel, marginBottom: 16, display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap", border: ds.empty ? `1.5px dashed ${C.orange}55` : `1px solid ${C.line}` }}>
            <div style={{ width: 40, height: 40, borderRadius: 11, flex: "0 0 auto", display: "grid", placeItems: "center", background: ds.empty ? C.orangeSoft : C.goldSoft }}><Database size={19} color={ds.empty ? C.orange : C.gold} /></div>
            <div style={{ flex: 1, minWidth: 220 }}>
              <div style={{ fontWeight: 800, fontSize: 14 }}>{t(ds.empty ? "cf.empty.title" : "cf.data.bar.title")}</div>
              <div style={{ fontSize: 12.5, color: C.sub, marginTop: 3, lineHeight: 1.55 }}>{t(ds.empty ? "cf.empty.desc" : "cf.data.bar.desc")}</div>
            </div>
            <button className="btn" onClick={() => setShowData(true)} style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 10, fontWeight: 800, fontSize: 13, color: "#1a1206", background: `linear-gradient(135deg, ${C.gold}, #C9892A)` }}><Database size={15} />{t("cf.data.button")}</button>
          </div>
        )}

        {/* CONNECT SOFTWARE (dropdown picker) */}
        <div className="card" style={{ ...panel, padding: 0, marginBottom: 16, overflow: "hidden" }}>
          <button className="btn" onClick={() => setSrcOpen((o) => !o)} style={{ width: "100%", display: "flex", alignItems: "center", gap: 9, flexWrap: "wrap", padding: "13px 16px", background: "transparent", color: C.txt, textAlign: "left" }}>
            <Link2 size={16} color={C.cyan} />
            <span style={{ fontWeight: 800, fontSize: 13.5 }}>{t("cf.connect")}</span>
            <span style={{ fontSize: 12, color: C.sub }}>{t("cf.connect.desc")}</span>
            <span style={{ marginLeft: "auto", display: "inline-flex", alignItems: "center", gap: 6, fontSize: 11, fontWeight: 700, color: connected.size ? C.green : C.sub, background: connected.size ? C.greenSoft : "rgba(255,255,255,.04)", padding: "4px 10px", borderRadius: 20 }}>
              {connected.size ? <><span style={{ width: 7, height: 7, borderRadius: 9, background: C.green }} />{t("cf.connected", { n: connected.size, m: DATA_SOURCES.length })}</> : t("cf.connectedNone")}
            </span>
            <ChevronDown size={17} color={C.sub} style={{ transition: "transform .25s", transform: srcOpen ? "rotate(180deg)" : "none" }} />
          </button>
          {srcOpen && (
            <div style={{ padding: "13px 16px 14px", display: "flex", gap: 9, flexWrap: "wrap", borderTop: `1px solid ${C.line}` }}>
              {DATA_SOURCES.map((s) => { const Ic = s.icon; const on = connected.has(s.id); return (
                <div key={s.id} style={{ flex: "1 1 200px", display: "flex", alignItems: "center", gap: 10, padding: "10px 12px", borderRadius: 12, background: C.panel2, border: `1px solid ${on ? s.color + "55" : C.line}`, transition: "all .2s" }}>
                  <div style={{ width: 32, height: 32, borderRadius: 8, flex: "0 0 auto", display: "grid", placeItems: "center", background: on ? s.color + "22" : "rgba(255,255,255,.05)" }}><Ic size={16} color={on ? s.color : C.sub} /></div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ fontWeight: 700, fontSize: 12.8, whiteSpace: "nowrap" }}>{s.name}</span>
                      <span style={{ fontSize: 9, fontWeight: 700, color: on ? s.color : C.sub, background: (on ? s.color : C.sub) + "1f", padding: "1px 6px", borderRadius: 5 }}>{s.kind}</span>
                    </div>
                    <div className="tnum" style={{ fontSize: 10.5, color: C.sub, marginTop: 2 }}>{on ? s.rows : t("cf.notConnected")}</div>
                  </div>
                  <button className="btn" onClick={() => toggleConnect(s.id)} style={{ flex: "0 0 auto", display: "inline-flex", alignItems: "center", gap: 5, padding: "6px 11px", borderRadius: 8, fontSize: 11.5, fontWeight: 700, color: on ? C.green : "#06202f", background: on ? C.greenSoft : s.color, border: on ? `1px solid ${C.green}55` : "none" }}>
                    {on ? <><CheckCircle2 size={13} />{t("cf.connDone")}</> : <><Plus size={13} />{t("cf.connBtn")}</>}
                  </button>
                </div>
              ); })}
            </div>
          )}
        </div>

        <div className="card" style={{ ...panel, padding: "13px 16px", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 11 }}><Zap size={16} color={C.orange} /><span style={{ fontWeight: 800, fontSize: 13.5 }}>{t("cf.stressTitle")}</span><span style={{ fontSize: 12, color: C.sub }}>{t("cf.stressDesc")}</span></div>
          <div style={{ display: "flex", gap: 9, flexWrap: "wrap" }}>
            {PRESETS.map((s) => <ScChip key={s.key} on={s.key === scKey} onClick={() => setScKey(s.key)} name={t("sc." + s.key)} desc={t("sc." + s.key + ".d")} c={C.orange} soft={C.orangeSoft} />)}
            <ScChip on={scKey === "custom"} onClick={() => setScKey("custom")} name={t("cf.custom")} desc={t("cf.customDesc")} c={C.violet} soft={C.violetSoft} icon={<SlidersHorizontal size={13} />} />
          </div>
          {scKey === "custom" && (
            <div style={{ marginTop: 13, paddingTop: 13, borderTop: `1px solid ${C.line}`, display: "grid", gap: 16, gridTemplateColumns: "repeat(auto-fit,minmax(220px,1fr))" }}>
              <Slider label={t("cf.sl.rev")} val={custom.rev} min={-0.5} max={0.1} step={0.01} fmt={(v) => `${v > 0 ? "+" : ""}${Math.round(v * 100)}%`} onChange={(v) => setCustom({ ...custom, rev: v })} c={custom.rev < 0 ? C.red : C.green} />
              <Slider label={t("cf.sl.cost")} val={custom.cost} min={0} max={0.2} step={0.01} fmt={(v) => `+${Math.round(v * 100)}%`} onChange={(v) => setCustom({ ...custom, cost: v })} c={C.orange} />
              <Slider label={t("cf.sl.delay")} val={custom.delay} min={0} max={4} step={1} fmt={(v) => `+${v} ${t("cf.weeks")}`} onChange={(v) => setCustom({ ...custom, delay: v })} c={C.gold} />
              <Slider label={t("cf.sl.haircut")} val={custom.haircut} min={0} max={0.5} step={0.01} fmt={(v) => `${Math.round(v * 100)}%`} onChange={(v) => setCustom({ ...custom, haircut: v })} c={C.red} />
            </div>
          )}
        </div>

        <div className="card" style={{ display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", padding: "16px 20px", borderRadius: 16, marginBottom: 16, background: rk.c + "1f", border: `1px solid ${rk.c}55` }}>
          <div style={{ width: 40, height: 40, borderRadius: 11, flex: "0 0 auto", display: "grid", placeItems: "center", background: `${rk.c}22` }}><rk.Icon size={22} color={rk.c} /></div>
          <div style={{ flex: 1, minWidth: 240 }}>
            <div style={{ fontWeight: 800, fontSize: 15.5, color: rk.c }}>{t("cf.earlyWarn", { p: Math.round(sim.pNeg * 100), lvl: t(RK_LABEL[rk.key]) })}</div>
            <div style={{ fontSize: 13.2, color: C.sub, marginTop: 3 }}>{sim.pNeg < 0.10 ? t("cf.safeMsg", { min: fmtVnd(sim.expMin), sc: t("sc." + (sc.key || "base")) }) : <>{t("cf.riskMsg.pre")} <b style={{ color: rk.c }}>{t("cf.week")} {sim.riskWeek + 1}</b> ({Math.round(sim.data[sim.riskWeek].negShare * 100)}%). {t("cf.riskMsg.trough")} <b className="tnum" style={{ color: rk.c }}>{fmtVnd(sim.expMin)}</b> · {t("cf.riskMsg.worst")} <b className="tnum">{fmtVnd(sim.worstMin)}</b>.</>}</div>
          </div>
        </div>

        <div style={{ display: "grid", gap: 14, gridTemplateColumns: "repeat(auto-fit,minmax(210px,1fr))", marginBottom: 16 }}>
          <Kpi label={t("cf.kpi.cash")} sub={t("cf.kpi.cash.sub")} value={fmtVnd(ds.startCash)} accent={C.gold} icon={<Wallet size={16} />} />
          <Kpi label={t("cf.kpi.pneg")} sub={t("cf.kpi.pneg.sub", { sc: t("sc." + (sc.key || "base")) })} value={`${Math.round(sim.pNeg * 100)}%`} accent={rk.c} icon={<rk.Icon size={16} />} />
          <Kpi label={t("cf.kpi.trough")} sub={t("cf.kpi.trough.sub")} value={fmtVnd(sim.expMin)} accent={sim.expMin < 0 ? C.red : C.green} icon={<TrendingDown size={16} />} />
          <Kpi label={t("cf.kpi.worst")} sub={t("cf.kpi.worst.sub")} value={fmtVnd(sim.worstMin)} accent={sim.worstMin < 0 ? C.red : C.cyan} icon={<AlertTriangle size={16} />} />
        </div>

        <div style={{ display: "grid", gap: 16, gridTemplateColumns: "minmax(0,1.7fr) minmax(0,1fr)" }}>
          <section className="card" style={panel}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", flexWrap: "wrap", gap: 8 }}><h3 style={h3}>{t("cf.chartTitle")}</h3><div style={{ display: "flex", gap: 14, fontSize: 12, color: C.sub }}><Legend swatch={C.gold} label={t("cf.leg.p50")} /><Legend swatch={C.gold} band label={t("cf.leg.band")} /></div></div>
            <div style={{ fontSize: 12.5, color: C.sub, margin: "4px 0 8px" }}>{t("cf.chartUnit")}</div>
            <div style={{ height: 320, marginLeft: -10 }}>
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={sim.data} margin={{ top: 8, right: 12, bottom: 4, left: 4 }}>
                  <defs><linearGradient id="gBand" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={C.gold} stopOpacity={0.28} /><stop offset="100%" stopColor={C.gold} stopOpacity={0.05} /></linearGradient></defs>
                  <CartesianGrid stroke={C.line2} vertical={false} />
                  <XAxis dataKey="name" tick={{ fill: C.sub, fontSize: 11.5, fontFamily: MONO }} axisLine={{ stroke: C.line }} tickLine={false} />
                  <YAxis tickFormatter={(v) => Math.round(v).toLocaleString("vi-VN")} tick={{ fill: C.sub, fontSize: 11.5, fontFamily: MONO }} axisLine={false} tickLine={false} width={48} domain={[Math.floor(yMin * 1.08), Math.ceil(yMax * 1.05)]} />
                  <Tooltip content={<TipBox />} cursor={{ stroke: C.line }} />
                  <Area dataKey="band" stroke="none" fill="url(#gBand)" isAnimationActive={false} />
                  <ReferenceLine y={0} stroke={C.red} strokeWidth={1.4} strokeDasharray="2 3" />
                  <Line type="monotone" dataKey="p50" stroke={C.gold} strokeWidth={2.8} dot={false} activeDot={{ r: 4, fill: C.gold }} animationDuration={500} />
                  <Line type="monotone" dataKey="p10" stroke={C.red} strokeWidth={1.3} strokeDasharray="4 4" dot={false} animationDuration={500} />
                  {sim.firstP50Neg >= 0 && <ReferenceDot x={sim.data[sim.firstP50Neg].name} y={sim.data[sim.firstP50Neg].p50} r={5} fill={C.red} stroke="#fff" strokeWidth={1.5} />}
                </ComposedChart>
              </ResponsiveContainer>
            </div>
          </section>
          <section className="card" style={{ ...panel, display: "flex", flexDirection: "column" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}><Activity size={17} color={rk.c} /><h3 style={h3}>{t("cf.detect")}</h3></div>
            <div style={{ textAlign: "center", marginBottom: 6 }}><div className="tnum" style={{ fontSize: 46, fontWeight: 800, color: rk.c, lineHeight: 1 }}>{Math.round(sim.pNeg * 100)}%</div><div style={{ fontSize: 12.5, color: C.sub, marginTop: 2 }}>{t("cf.detectSub")}</div></div>
            <div style={{ position: "relative", height: 10, borderRadius: 6, margin: "14px 2px 6px", background: `linear-gradient(90deg, ${C.green}, ${C.gold} 35%, ${C.orange} 60%, ${C.red})` }}><div style={{ position: "absolute", top: -5, left: `calc(${clamp(sim.pNeg, 0, 1) * 100}% - 2px)`, width: 4, height: 20, borderRadius: 3, background: "#fff", boxShadow: "0 0 0 2px rgba(0,0,0,.4)" }} /></div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10.5, color: C.sub, marginBottom: 14 }}><span>{t("cf.lvl.safe2")}</span><span>{t("cf.lvl.watch")}</span><span>{t("cf.lvl.warn2")}</span><span>{t("cf.lvl.crit")}</span></div>
            <div style={{ fontSize: 12, color: C.sub, marginBottom: 7, fontWeight: 700 }}>{t("cf.weeklyRisk")}</div>
            <div style={{ display: "flex", gap: 3, alignItems: "flex-end", height: 64, marginBottom: 4 }}>
              {sim.data.map((d) => <div key={d.idx} title={`${t("cf.week")} ${d.idx + 1}: ${Math.round(d.negShare * 100)}%`} style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "flex-end", height: "100%" }}><div style={{ height: `${Math.max(6, d.negShare * 100)}%`, background: heat(d.negShare, C), borderRadius: 3, transition: "height .4s, background .4s", outline: d.idx === sim.riskWeek && sim.pNeg >= 0.1 ? "1.5px solid #fff" : "none" }} /></div>)}
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: 9.5, color: C.sub, fontFamily: MONO }}><span>T1</span><span>T7</span><span>T13</span></div>
            <div style={{ marginTop: "auto", paddingTop: 13 }}><Stat label={t("cf.riskWeek")} value={sim.pNeg >= 0.05 ? `${t("cf.week")} ${sim.riskWeek + 1} · ${ds.ranges[sim.riskWeek]}` : "—"} c={rk.c} /><Stat label={t("cf.evSelected")} value={fmtVnd(totalEV)} c={C.cyan} /></div>
          </section>
        </div>

        <section className="card" style={{ ...panel, marginTop: 16, borderColor: "rgba(169,139,255,.35)" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}><Wand2 size={17} color={C.violet} /><h3 style={h3}>{t("cf.opt.title")}</h3></div>
          <div style={{ fontSize: 12.5, color: C.sub, margin: "4px 0 13px" }}>{t("cf.opt.desc1")} <b style={{ color: C.txt }}>{t("cf.opt.desc2")}</b> {t("cf.opt.desc3")}</div>
          <div style={{ display: "flex", gap: 14, flexWrap: "wrap", alignItems: "center" }}>
            <span style={{ fontSize: 12.5, color: C.sub, fontWeight: 600 }}>{t("cf.opt.threshold")}</span>
            <div style={{ display: "flex", gap: 7 }}>{[0.05, 0.10, 0.20].map((tv) => <button key={tv} className="btn" onClick={() => setTarget(tv)} style={{ padding: "7px 14px", borderRadius: 9, fontWeight: 700, fontSize: 12.5, color: target === tv ? "#1a1206" : C.txt, background: target === tv ? C.violet : C.panel2, border: `1px solid ${target === tv ? C.violet : C.line}` }}>≤ {Math.round(tv * 100)}%</button>)}</div>
            <button className="btn" onClick={runOptimize} style={{ marginLeft: "auto", display: "inline-flex", alignItems: "center", gap: 8, padding: "10px 18px", borderRadius: 10, fontWeight: 800, fontSize: 13.5, color: "#160f24", background: `linear-gradient(135deg, ${C.violet}, #7E5CF0)`, boxShadow: "0 8px 22px rgba(126,92,240,.3)" }}><Wand2 size={16} />{t("cf.opt.run")}</button>
          </div>
          {plan && (
            <div style={{ marginTop: 14, padding: "13px 15px", borderRadius: 12, background: plan.feasible ? C.violetSoft : C.redSoft, border: `1px solid ${plan.feasible ? "rgba(169,139,255,.4)" : "rgba(255,82,105,.4)"}` }}>
              {plan.feasible ? <><div style={{ fontWeight: 800, fontSize: 14, color: C.violet, marginBottom: 5 }}>✓ {t("cf.opt.call", { n: plan.count, names: plan.ids.map((id) => shortName(ds.recv.find((r) => r.id === id))).join(", ") })}</div><div style={{ fontSize: 13, color: C.sub }}>{t("cf.opt.from")} <b className="tnum" style={{ color: C.red }}>{Math.round(plan.before * 100)}%</b> ➜ <b className="tnum" style={{ color: C.green }}>{Math.round(plan.pNeg * 100)}%</b> {t("cf.opt.applied", { t: Math.round(target * 100) })}</div></> : <div style={{ fontSize: 13.3, color: C.red, fontWeight: 600 }}>⚠ {t("cf.opt.fail")} <b className="tnum">{Math.round(plan.pNeg * 100)}%</b> {t("cf.opt.failTail", { t: Math.round(target * 100) })}</div>}
            </div>
          )}
        </section>

        <section className="card" style={{ ...panel, marginTop: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}><Phone size={17} color={C.gold} /><h3 style={h3}>{t("cf.list.title")}</h3></div>
          <div style={{ fontSize: 12.5, color: C.sub, margin: "4px 0 14px" }}>{t("cf.list.desc")}{sc.haircut > 0 && <b style={{ color: C.orange }}> {t("cf.list.scenario", { sc: t("sc." + (sc.key || "base")), p: Math.round(sc.haircut * 100) })}</b>}</div>
          <div style={{ overflowX: "auto" }}><div style={{ minWidth: 720 }}>
            <div style={{ display: "grid", gridTemplateColumns: "minmax(0,2.3fr) 86px 90px minmax(150px,1.4fr) 110px 78px", gap: 10, padding: "0 12px 8px", fontSize: 11, color: C.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".03em" }}><span>{t("cf.col.customer")}</span><span style={{ textAlign: "right" }}>{t("cf.col.overdue")}</span><span style={{ textAlign: "right" }}>{t("cf.col.debt")}</span><span>{t("cf.col.prob")}</span><span style={{ textAlign: "right" }}>{t("cf.col.ev")}</span><span style={{ textAlign: "center" }}>{t("cf.col.collectW")}</span></div>
            {ds.real && ds.recv.length === 0 && (
              <div style={{ padding: "18px 12px", fontSize: 12.8, color: C.sub, textAlign: "center" }}>{t("cf.recv.empty")}</div>
            )}
            {ds.recv.map((r) => {
              const on = selected.has(r.id); const pEff = clamp(r.p * (1 - sc.haircut), 0, 0.99); const ev = r.amount * pEff, w = Math.min(13, r.collectWeek + sc.delay + 1); const pc = pEff >= 0.8 ? C.green : pEff >= 0.6 ? C.gold : C.red;
              return (
                <button key={r.id} onClick={() => toggle(r.id)} className="rowh" style={{ width: "100%", textAlign: "left", cursor: "pointer", display: "grid", gridTemplateColumns: "minmax(0,2.3fr) 86px 90px minmax(150px,1.4fr) 110px 78px", gap: 10, alignItems: "center", padding: "11px 12px", borderRadius: 12, marginBottom: 7, color: C.txt, background: on ? C.goldSoft : C.panel2, border: `1px solid ${on ? "rgba(245,184,61,.4)" : C.line}`, transition: "all .15s" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 11, minWidth: 0 }}>
                    <div style={{ width: 20, height: 20, borderRadius: 6, flex: "0 0 auto", display: "grid", placeItems: "center", border: `1.6px solid ${on ? C.gold : C.sub}`, background: on ? C.gold : "transparent" }}>{on && <CheckCircle2 size={14} color="#1a1206" strokeWidth={3} />}</div>
                    <div style={{ minWidth: 0 }}><div style={{ display: "flex", gap: 7, alignItems: "center" }}><span style={{ fontWeight: 700, fontSize: 13, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{r.name}</span>{r.ai && <span style={{ flex: "0 0 auto", fontSize: 9, fontWeight: 800, padding: "2px 5px", borderRadius: 5, background: C.goldSoft, color: C.gold }}>{t("cf.aiSuggest")}</span>}</div><div className="tnum" style={{ fontSize: 11, color: C.sub, marginTop: 2 }}>{r.code} · {t("cf.onTime", { p: Math.round(r.onTime * 100) })}</div></div>
                  </div>
                  <span className="tnum" style={{ textAlign: "right", fontSize: 12.5, color: r.days >= 30 ? C.red : C.sub }}>{r.days} {t("cf.days")}</span>
                  <span className="tnum" style={{ textAlign: "right", fontWeight: 700, fontSize: 13 }}>{fmtTr(r.amount)}</span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}><div style={{ flex: 1, height: 7, borderRadius: 5, background: "rgba(255,255,255,.08)", overflow: "hidden" }}><div style={{ width: `${pEff * 100}%`, height: "100%", background: pc, borderRadius: 5, transition: "width .4s" }} /></div><span className="tnum" style={{ fontSize: 12, fontWeight: 700, color: pc, width: 34, textAlign: "right" }}>{Math.round(pEff * 100)}%</span></div>
                  <span className="tnum" style={{ textAlign: "right", fontWeight: 700, fontSize: 13, color: C.cyan }}>{fmtTr(ev)}</span>
                  <span className="tnum" style={{ textAlign: "center", fontSize: 12.5, color: C.sub }}>T{w}</span>
                </button>
              );
            })}
          </div></div>
        </section>

        <section className="card" style={{ ...panel, marginTop: 16 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}><Tag size={17} color={C.cyan} /><h3 style={h3}>{t("cf.classTitle")}</h3></div>
          <div style={{ fontSize: 12.5, color: C.sub, margin: "4px 0 14px" }}>{t(DEMO_MODE ? "cf.classDesc" : "cf.classDesc.real")}</div>
          {!DEMO_MODE && classification.length === 0 && (
            <div style={{ fontSize: 12.5, color: C.sub, padding: "6px 2px" }}>{t("cf.class.empty")}</div>
          )}
          <div style={{ display: "grid", gap: 10, gridTemplateColumns: "repeat(auto-fill,minmax(232px,1fr))" }}>
            {classification.map((c) => { const col = c.kind === "in" ? C.green : c.kind === "out" ? C.red : C.cyan; return (<div key={c.code} style={{ padding: "12px 13px", borderRadius: 12, background: C.panel2, border: `1px solid ${C.line}` }}><div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 7 }}><span className="tnum" style={{ fontWeight: 800, fontSize: 14, color: col }}>{c.code}</span><span style={{ width: 6, height: 6, borderRadius: 9, background: col }} /><span style={{ fontSize: 11.6, fontWeight: 600 }}>{t(c.key)}</span></div><div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}><span className="tnum" style={{ fontSize: 11.5, color: C.sub }}>{c.count} {t("cf.entries")}</span>{c.total > 0 && <span className="tnum" style={{ fontSize: 12.5, fontWeight: 700 }}>{fmtVnd(c.total)}</span>}</div></div>); })}
          </div>
        </section>

        <footer style={{ marginTop: 18, fontSize: 11.5, color: C.sub, textAlign: "center", lineHeight: 1.6 }}>{t("cf.footer")}</footer>
      </div>
    </div>
  );
}

/* ================= REPORT (white, print-ready A4) ================= */
function Report({ sim, sc, selected, totalEV, ds = DEMO_DS, onClose }) {
  const { t } = useT();
  const { company } = useCompany();
  const currency = company?.currency || "VND";
  const fmtVnd = (m) => fmtMoneyM(m, currency);
  const fmtTr = (m) => fmtCompactM(m, currency);
  const rk = riskLevel(sim.pNeg, L);
  const sel = ds.recv.filter((r) => selected.has(r.id));
  const yMin = Math.min(0, ...sim.data.map((d) => d.p10)); const yMax = Math.max(START_CASH, ...sim.data.map((d) => d.p90));
  const today = new Date().toLocaleDateString();
  const scName = sc.key === "custom" ? t("cf.custom") : t("sc." + sc.key);
  const verdict = sim.pNeg < 0.10
    ? t("rp.verdict.safe", { sc: scName, p: Math.round(sim.pNeg * 100), min: fmtVnd(sim.expMin) })
    : t("rp.verdict.risk", { sc: scName, p: Math.round(sim.pNeg * 100), lvl: t(RK_LABEL[rk.key]), w: sim.riskWeek + 1, range: ds.ranges[sim.riskWeek], min: fmtVnd(sim.expMin), worst: fmtVnd(sim.worstMin), n: sel.length, ev: fmtVnd(totalEV) });

  return (
    <div style={{ background: "#5b6376", minHeight: "100vh", fontFamily: UI, padding: "0 0 40px" }}>
      <style>{`
        @page { size: A4; margin: 13mm; }
        @media print { .noprint{display:none!important} .paper{box-shadow:none!important;margin:0!important;width:auto!important} body{background:#fff} .report-bg{background:#fff!important;padding:0!important} }
        .paper table{border-collapse:collapse;width:100%}
      `}</style>
      {/* toolbar */}
      <div className="noprint" style={{ position: "sticky", top: 0, zIndex: 5, background: "#0A0E18", borderBottom: `1px solid ${C.line}`, padding: "12px clamp(14px,3vw,30px)", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <button className="btn" onClick={onClose} style={{ display: "inline-flex", alignItems: "center", gap: 7, fontSize: 13, fontWeight: 700, color: C.txt, background: "rgba(255,255,255,.06)", border: `1px solid ${C.line}`, padding: "9px 15px", borderRadius: 10 }}><X size={15} />{t("rp.back")}</button>
        <div style={{ fontSize: 12.5, color: C.sub }}>{t("rp.tip")} <b style={{ color: C.txt }}>{t("rp.saveAs")}</b></div>
        <button className="btn" onClick={() => window.print()} style={{ display: "inline-flex", alignItems: "center", gap: 8, fontSize: 13.5, fontWeight: 800, color: "#06202f", background: `linear-gradient(135deg, ${C.cyan}, #2E9BD6)`, padding: "10px 18px", borderRadius: 10 }}><Printer size={16} />{t("rp.print")}</button>
      </div>

      <div className="report-bg" style={{ padding: "26px 16px" }}>
        <div className="paper" style={{ width: 794, maxWidth: "100%", margin: "0 auto", background: L.paper, color: L.ink, padding: "34px 38px 30px", borderRadius: 4, boxShadow: "0 20px 60px rgba(0,0,0,.4)", fontSize: 13 }}>
          {/* letterhead */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", borderBottom: `2px solid ${L.gold}`, paddingBottom: 14 }}>
            <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
              <div style={{ width: 40, height: 40, borderRadius: 9, display: "grid", placeItems: "center", background: `linear-gradient(135deg, ${L.gold}, #9c6a14)` }}><Wallet size={21} color="#fff" strokeWidth={2.3} /></div>
              <div><div style={{ fontFamily: DISP, fontWeight: 800, fontSize: 17, color: L.ink }}>LUXORA</div><div style={{ fontSize: 10.5, color: L.sub }}>{t("rp.appsub")}</div></div>
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontFamily: DISP, fontWeight: 800, fontSize: 15, color: L.ink, letterSpacing: ".01em" }}>{t("rp.title")}</div>
              <div className="tnum" style={{ fontSize: 11, color: L.sub, marginTop: 3 }}>{t("rp.date")} {today} · {t("rp.scenario")} {scName}</div>
            </div>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11.5, color: L.sub, margin: "10px 0 4px" }}>
            <span><b style={{ color: L.ink }}>{t("rp.company")}</b> {COMPANY}</span>
            <span className="tnum"><b style={{ color: L.ink }}>{t("rp.period")}</b> {ds.ranges[0].split("–")[0]} – {ds.ranges[12].split("–")[1]} (13 {t("cf.weeks")})</span>
          </div>

          {/* risk summary */}
          <div style={{ display: "flex", gap: 14, marginTop: 14, borderLeft: `5px solid ${rk.c}`, background: L.soft, borderRadius: 8, padding: "14px 16px" }}>
            <div style={{ flex: "0 0 150px", textAlign: "center", borderRight: `1px solid ${L.hair}`, paddingRight: 14 }}>
              <div style={{ fontSize: 10.5, color: L.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: ".04em" }}>{t("rp.pneg")}</div>
              <div className="tnum" style={{ fontSize: 40, fontWeight: 800, color: rk.c, lineHeight: 1.1 }}>{Math.round(sim.pNeg * 100)}%</div>
              <div style={{ display: "inline-block", fontSize: 11, fontWeight: 800, color: "#fff", background: rk.c, padding: "2px 10px", borderRadius: 20 }}>{t(RK_LABEL[rk.key])}</div>
            </div>
            <div style={{ flex: 1, display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px 18px", alignContent: "center" }}>
              <RStat label={t("rp.cashStart")} v={fmtVnd(START_CASH)} c={L.gold} />
              <RStat label={t("rp.trough")} v={fmtVnd(sim.expMin)} c={sim.expMin < 0 ? L.red : L.green} />
              <RStat label={t("rp.riskWeek")} v={sim.pNeg >= 0.05 ? `${t("cf.week")} ${sim.riskWeek + 1}` : "—"} c={rk.c} />
              <RStat label={t("rp.worst")} v={fmtVnd(sim.worstMin)} c={sim.worstMin < 0 ? L.red : L.cyan} />
            </div>
          </div>

          {/* verdict */}
          <div style={{ marginTop: 14 }}>
            <SecTitle n="1" t={t("rp.sec1")} />
            <p style={{ margin: "6px 0 0", fontSize: 12.3, lineHeight: 1.65, color: "#2a3854" }}>{verdict}</p>
          </div>

          {/* chart */}
          <div style={{ marginTop: 16 }}>
            <SecTitle n="2" t={t("rp.sec2")} />
            <div style={{ fontSize: 10.8, color: L.sub, margin: "3px 0 2px" }}>{t("rp.chartNote")}</div>
            <div style={{ height: 220, marginLeft: -14 }}>
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={sim.data} margin={{ top: 6, right: 10, bottom: 2, left: 4 }}>
                  <defs><linearGradient id="rband" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={L.gold} stopOpacity={0.32} /><stop offset="100%" stopColor={L.gold} stopOpacity={0.06} /></linearGradient></defs>
                  <CartesianGrid stroke={L.hair} vertical={false} />
                  <XAxis dataKey="name" tick={{ fill: L.sub, fontSize: 10, fontFamily: MONO }} axisLine={{ stroke: L.hair }} tickLine={false} />
                  <YAxis tickFormatter={(v) => Math.round(v).toLocaleString("vi-VN")} tick={{ fill: L.sub, fontSize: 10, fontFamily: MONO }} axisLine={false} tickLine={false} width={42} domain={[Math.floor(yMin * 1.08), Math.ceil(yMax * 1.05)]} />
                  <Area dataKey="band" stroke="none" fill="url(#rband)" isAnimationActive={false} />
                  <ReferenceLine y={0} stroke={L.red} strokeWidth={1.3} strokeDasharray="2 3" />
                  <Line type="monotone" dataKey="p50" stroke={L.gold} strokeWidth={2.4} dot={false} isAnimationActive={false} />
                  <Line type="monotone" dataKey="p10" stroke={L.red} strokeWidth={1.1} strokeDasharray="4 4" dot={false} isAnimationActive={false} />
                  {sim.firstP50Neg >= 0 && <ReferenceDot x={sim.data[sim.firstP50Neg].name} y={sim.data[sim.firstP50Neg].p50} r={4} fill={L.red} stroke="#fff" strokeWidth={1.4} />}
                </ComposedChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* call list */}
          <div style={{ marginTop: 14, pageBreakInside: "avoid" }}>
            <SecTitle n="3" t={t("rp.sec3", { n: sel.length })} />
            <table style={{ marginTop: 6, fontSize: 11.5 }}>
              <thead><tr style={{ background: L.ink, color: "#fff" }}>
                {[t("rp.th.customer"), t("rp.th.acc"), t("rp.th.debt"), t("rp.th.overdue"), t("rp.th.prob"), t("rp.th.ev"), t("rp.th.week"), t("rp.th.plan")].map((h, i) => <th key={i} style={{ padding: "7px 9px", textAlign: i === 0 ? "left" : i >= 2 && i <= 5 ? "right" : "center", fontSize: 10.5, fontWeight: 700 }}>{h}</th>)}
              </tr></thead>
              <tbody>
                {ds.recv.map((r, idx) => { const on = selected.has(r.id); const pEff = clamp(r.p * (1 - sc.haircut), 0, 0.99); const pc = pEff >= 0.8 ? L.green : pEff >= 0.6 ? L.gold : L.red;
                  return (<tr key={r.id} style={{ background: on ? "rgba(197,137,27,.09)" : idx % 2 ? L.soft : "#fff", borderBottom: `1px solid ${L.hair}` }}>
                    <td style={{ padding: "7px 9px", fontWeight: 600 }}>{r.name}{r.ai && <span style={{ marginLeft: 6, fontSize: 8.5, fontWeight: 800, color: L.gold, border: `1px solid ${L.gold}`, borderRadius: 4, padding: "1px 4px" }}>AI</span>}</td>
                    <td className="tnum" style={{ padding: "7px 9px", color: L.sub }}>{r.code}</td>
                    <td className="tnum" style={{ padding: "7px 9px", textAlign: "right", fontWeight: 700 }}>{fmtTr(r.amount)}</td>
                    <td className="tnum" style={{ padding: "7px 9px", textAlign: "right", color: r.days >= 30 ? L.red : L.sub }}>{r.days} {t("cf.days")}</td>
                    <td className="tnum" style={{ padding: "7px 9px", textAlign: "right", fontWeight: 700, color: pc }}>{Math.round(pEff * 100)}%</td>
                    <td className="tnum" style={{ padding: "7px 9px", textAlign: "right", fontWeight: 700, color: L.cyan }}>{fmtTr(r.amount * pEff)}</td>
                    <td className="tnum" style={{ padding: "7px 9px", textAlign: "center", color: L.sub }}>T{Math.min(13, r.collectWeek + sc.delay + 1)}</td>
                    <td style={{ padding: "7px 9px", textAlign: "center" }}>{on ? <Check size={15} color={L.green} strokeWidth={3} style={{ verticalAlign: "middle" }} /> : <span style={{ color: L.hair }}>—</span>}</td>
                  </tr>); })}
                <tr style={{ borderTop: `2px solid ${L.ink}` }}>
                  <td colSpan={5} style={{ padding: "7px 9px", textAlign: "right", fontWeight: 700, color: L.sub }}>{t("rp.totalRow")}</td>
                  <td className="tnum" style={{ padding: "7px 9px", textAlign: "right", fontWeight: 800, color: L.green }}>{fmtTr(totalEV)}</td>
                  <td colSpan={2}></td>
                </tr>
              </tbody>
            </table>
          </div>

          {/* signatures */}
          <div style={{ marginTop: 26, display: "flex", justifyContent: "space-around", textAlign: "center", pageBreakInside: "avoid" }}>
            {[t("rp.sig.maker"), t("rp.sig.chief"), t("rp.sig.director")].map((s) => (
              <div key={s} style={{ width: 170 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: L.ink }}>{s}</div>
                <div style={{ fontSize: 9.5, color: L.sub, fontStyle: "italic" }}>{t("rp.sig.note")}</div>
                <div style={{ height: 46 }} />
              </div>
            ))}
          </div>

          <div style={{ marginTop: 16, paddingTop: 10, borderTop: `1px solid ${L.hair}`, fontSize: 9.5, color: L.sub, textAlign: "center", lineHeight: 1.5 }}>
            {t("rp.disclaimer")}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ---------- shared sub components ---------- */
const panel = { background: C.panel, border: `1px solid ${C.line}`, borderRadius: 18, padding: "18px 18px 16px", boxShadow: "0 18px 40px -28px rgba(0,0,0,.7)" };
const h3 = { margin: 0, fontFamily: DISP, fontWeight: 700, fontSize: 16, letterSpacing: "-0.01em", color: C.txt };
const expBtn = (c, soft) => ({ display: "inline-flex", alignItems: "center", gap: 7, fontSize: 12.8, fontWeight: 700, padding: "9px 15px", borderRadius: 10, color: c, background: soft, border: `1px solid ${c}44` });
function SecTitle({ n, t }) { return <div style={{ display: "flex", alignItems: "center", gap: 8 }}><span style={{ width: 19, height: 19, borderRadius: 5, background: L.ink, color: "#fff", fontSize: 11, fontWeight: 800, display: "grid", placeItems: "center" }}>{n}</span><span style={{ fontFamily: DISP, fontWeight: 700, fontSize: 13.5, color: L.ink }}>{t}</span></div>; }
function RStat({ label, v, c }) { return <div><div style={{ fontSize: 10.3, color: L.sub, fontWeight: 600 }}>{label}</div><div className="tnum" style={{ fontSize: 15, fontWeight: 800, color: c }}>{v}</div></div>; }
function ScChip({ on, onClick, name, desc, c, soft, icon }) { return (<button className="btn" onClick={onClick} style={{ textAlign: "left", flex: "1 1 190px", padding: "10px 13px", borderRadius: 12, color: C.txt, background: on ? soft : C.panel2, border: `1px solid ${on ? c + "88" : C.line}` }}><div style={{ display: "flex", alignItems: "center", gap: 6, fontWeight: 800, fontSize: 13.3, color: on ? c : C.txt }}>{icon}{name}</div><div style={{ fontSize: 11.3, color: C.sub, marginTop: 2 }}>{desc}</div></button>); }
function Slider({ label, val, min, max, step, fmt, onChange, c }) { return (<div><div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}><span style={{ fontSize: 12.3, color: C.sub, fontWeight: 600 }}>{label}</span><span className="tnum" style={{ fontSize: 12.8, fontWeight: 800, color: c }}>{fmt(val)}</span></div><input type="range" min={min} max={max} step={step} value={val} onChange={(e) => onChange(parseFloat(e.target.value))} style={{ width: "100%" }} /></div>); }
function Kpi({ label, sub, value, accent, icon }) { return (<div className="card" style={{ ...panel, padding: "15px 16px" }}><div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 9 }}><span style={{ fontSize: 12.3, color: C.sub, fontWeight: 600 }}>{label}</span><span style={{ color: accent }}>{icon}</span></div><div className="tnum" style={{ fontSize: 21, fontWeight: 800, color: accent, letterSpacing: "-0.02em" }}>{value}</div><div style={{ fontSize: 11.3, color: C.sub, marginTop: 4 }}>{sub}</div></div>); }
function Stat({ label, value, c }) { return (<div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "9px 0", borderTop: `1px solid ${C.line}` }}><span style={{ fontSize: 12, color: C.sub }}>{label}</span><span className="tnum" style={{ fontSize: 13, fontWeight: 700, color: c }}>{value}</span></div>); }
function Legend({ swatch, label, band }) { return <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}><span style={{ width: 16, height: band ? 10 : 0, borderRadius: band ? 3 : 0, background: band ? `${swatch}44` : "none", borderTop: band ? "none" : `3px solid ${swatch}` }} />{label}</span>; }
function TipBox({ active, payload }) { const { t } = useT(); const { company } = useCompany(); const fmtVnd = (m) => fmtMoneyM(m, company?.currency || "VND"); if (!active || !payload || !payload.length) return null; const d = payload[0].payload; return (<div style={{ background: "#0A0F1C", border: `1px solid ${C.line}`, borderRadius: 12, padding: "11px 13px", fontFamily: UI, boxShadow: "0 14px 30px rgba(0,0,0,.5)", minWidth: 190 }}><div style={{ fontWeight: 800, fontSize: 13 }}>{t("cf.week")} {d.idx + 1} <span style={{ color: C.sub, fontWeight: 500 }}>· {d.range}</span></div><Row k={t("cf.tip.p50")} v={fmtVnd(d.p50)} c={d.p50 < 0 ? C.red : C.gold} /><Row k={t("cf.tip.p90")} v={fmtVnd(d.p90)} c={C.green} /><Row k={t("cf.tip.p10")} v={fmtVnd(d.p10)} c={d.p10 < 0 ? C.red : C.sub} /><div style={{ height: 1, background: C.line, margin: "7px 0" }} /><Row k={t("cf.tip.risk")} v={`${Math.round(d.negShare * 100)}%`} c={heat(d.negShare, C)} />{OUT_NOTES[d.idx] && <div style={{ fontSize: 11, color: C.sub, marginTop: 6 }}>★ {t(OUT_NOTES[d.idx])}</div>}</div>); }
function Row({ k, v, c }) { return <div style={{ display: "flex", justifyContent: "space-between", gap: 18, fontSize: 12, marginTop: 5 }}><span style={{ color: C.sub }}>{k}</span><span className="tnum" style={{ color: c, fontWeight: 700 }}>{v}</span></div>; }

/* ================= FP&A AUTOMATION MODULE (embedded) ================= */
/* ---------- palette ---------- */
const C_FPA = {
  bg: "#0A0E18", panel: "#121A2B", panel2: "#0E1422",
  line: "rgba(255,255,255,0.08)", line2: "rgba(255,255,255,0.045)",
  txt: "#E9EDF6", sub: "#8A93AA",
  gold: "#F5B83D", goldSoft: "rgba(245,184,61,0.14)",
  green: "#37D29A", greenSoft: "rgba(55,210,154,0.12)",
  red: "#FF5269", redSoft: "rgba(255,82,105,0.13)",
  orange: "#FF9A3D", orangeSoft: "rgba(255,154,61,0.13)",
  cyan: "#54C7FF", cyanSoft: "rgba(84,199,255,0.12)",
  violet: "#A98BFF", violetSoft: "rgba(169,139,255,0.14)",
};
const MONO_FPA = "'IBM Plex Mono', ui-monospace, monospace";
