/* ---------- base cashflow (triệu đồng) ---------- */
const START_FPA = 540;
const INFLOW_FPA  = [168, 160, 175, 152, 170, 162, 156, 178, 160, 168, 164, 172, 178];
const OUTFLOW_FPA = [188, 146, 228, 332, 196, 392, 214, 340, 196, 152, 148, 344, 198];

/* deterministic noise for confidence band width (LSTM uncertainty grows with horizon) */
function bandWidth_FPA(i) { return 14 + i * 3.4; }

/* scenario multipliers */
const SCEN_FPA = {
  best: { name: "Best-case", icon: Sun, color: C_FPA.green, rev: 0.08, cost: -0.03, label: "fpa.scen.best" },
  base: { name: "Base-case", icon: CloudRain, color: C_FPA.cyan, rev: 0, cost: 0, label: "fpa.scen.base" },
  stress: { name: "Stress-test", icon: CloudLightning, color: C_FPA.red, rev: -0.28, cost: 0.09, label: "fpa.scen.stress" },
};

function buildForecast_FPA() {
  // each scenario: cumulative balance + p10/p90 band on base
  const out = {};
  for (const key of Object.keys(SCEN_FPA)) {
    const s = SCEN_FPA[key]; let bal = START_FPA; const arr = [];
    for (let i = 0; i < 13; i++) {
      bal += INFLOW_FPA[i] * (1 + s.rev) - OUTFLOW_FPA[i] * (1 + s.cost);
      arr.push(Math.round(bal));
    }
    out[key] = arr;
  }
  // base band
  const base = out.base;
  const series = base.map((b, i) => ({
    name: `T${i + 1}`, idx: i,
    base: b, best: out.best[i], stress: out.stress[i],
    band: [Math.round(b - bandWidth_FPA(i)), Math.round(b + bandWidth_FPA(i))],
    lo: Math.round(b - bandWidth_FPA(i)), hi: Math.round(b + bandWidth_FPA(i)),
  }));
  const trough = (a) => { let m = Infinity, w = 0; a.forEach((v, i) => { if (v < m) { m = v; w = i; } }); return { m, w }; };
  return {
    series,
    troughs: { best: trough(out.best), base: trough(out.base), stress: trough(out.stress) },
    firstNeg: { best: out.best.findIndex((v) => v < 0), base: out.base.findIndex((v) => v < 0), stress: out.stress.findIndex((v) => v < 0) },
  };
}

