                {isSent ? <><CheckCircle2 size={15} />{t("col.sent", { ch: CHANNELS_COL.find((c) => c.id === channel).name })}</> : <><Send size={15} />{t("col.send", { ch: CHANNELS_COL.find((c) => c.id === channel).name })}</>}
