                <div style={{ display: "flex", gap: 4 }}>
                  {AGENTS_PR.map((a) => <div key={a.id} style={{ flex: 1, height: 7, borderRadius: 4, background: active.has(a.id) ? a.color : "rgba(255,255,255,.08)", transition: "background .3s" }} />)}
                </div>
